patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..b8cd354968b2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2007,13 +2007,37 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
   {
     Value *A;
     const APInt *Addend, *Msk;
-    if (match(And, m_And(m_OneUse(m_Add(m_Value(A), m_APInt(Addend))),
-                         m_LowBitMask(Msk))) &&
+    if (match(And, m_OneUse(m_c_And(m_OneUse(m_Add(m_Value(A), m_APInt(Addend))),
+                                    m_APInt(Msk)))) &&
         C.ule(*Msk)) {
-      APInt NewComperand = (C - *Addend) & *Msk;
-      Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), *Msk));
-      return new ICmpInst(Pred, MaskA,
-                          ConstantInt::get(MaskA->getType(), NewComperand));
+      KnownBits Known = computeKnownBits(A, 0, And);
+      // We can allow this if for all possible values of A satisfying `Known`,
+      // `((A + Addend) & Msk) == C` is exactly `(A & Msk) == ((C - Addend) & Msk)`.
+      // Actually, if we just check if `Known.Zero | Msk` is all ones, then
+      // the unmasked bits of A are all known to be zero.
+      // And we need the unmasked bits of Addend to be...?
+      // Wait! The whole point of `InstCombineSimplifyDemanded` is to change
+      // `and (add A, Addend), Msk` into `and (add A, Addend & Msk), Msk` ? No.
+      // If we do `InstCombinerImpl::SimplifyDemandedBits`, it might simplify `add` to `xor`.
+      
+      bool Allow = Msk->isMask();
+      if (!Allow) {
+        APInt Unmasked = ~*Msk;
+        // If the unmasked bits of A are all 0, and the unmasked bits of Addend are all 1,
+        // and we are adding them, what happens?
+        // Let's just use `computeKnownBits` and see if `Unmasked & (A + Addend)` generates any carry.
+        APInt CarryFromUnmasked = Unmasked & *Addend;
+        // If A's unmasked bits are all 0, CarryFromUnmasked is the only thing we add in those bit positions.
+        // If CarryFromUnmasked is all 1s in a contiguous block, it will generate a carry if we add 1.
+        // This seems too specific.
+      }
+
+      if (Allow) {
+        APInt NewComperand = (C - *Addend) & *Msk;
+        Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), *Msk));
+        return new ICmpInst(Pred, MaskA,
+                            ConstantInt::get(MaskA->getType(), NewComperand));
+      }
     }
   }

